+		tmpDir := t.TempDir()
+		if err := os.MkdirAll(filepath.Join(tmpDir, ".beads"), 0755); err != nil {
+			t.Fatal(err)
+		}
+		if err := StaleLockFiles(tmpDir); err != nil {
+			t.Errorf("expected no error for empty .beads dir, got %v", err)
+		}
